ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?cert_name_g (COUNT(*) AS ?agg) WHERE {
  ?certification a :Certification .
  ?job_post a :JobPostings .
  ?job_post p:hasCertification ?certification .
  ?certification p:cert_name ?cert_name_g .
}
GROUP BY ?cert_name_g }
  full: { SELECT ?level_name_g ?cert_name_g (COUNT(*) AS ?agg) WHERE {
  ?degree_level a :Degree_Level .
  ?job_post a :JobPostings .
  ?job_post p:hasDegree_Level ?degree_level .
  ?certification a :Certification .
  ?job_post p:hasCertification ?certification .
  ?degree_level p:level_name ?level_name_g .
  ?certification p:cert_name ?cert_name_g .
}
GROUP BY ?level_name_g ?cert_name_g }
  component_2: { SELECT ?level_name_g (COUNT(*) AS ?agg) WHERE {
  ?degree_level a :Degree_Level .
  ?job_post a :JobPostings .
  ?job_post p:hasDegree_Level ?degree_level .
  ?degree_level p:level_name ?level_name_g .
}
GROUP BY ?level_name_g }
}

